        wAmount = getStakingRate(time).mul(amount).div(1e18);
        require(wAmount > 0, "invalid lockup");

        v.hakkaAmount = amount;
        v.wAmount = wAmount;
        v.unlockTime = block.timestamp.add(time);

        stakedHakka[to] = stakedHakka[to].add(amount);
        votingPower[to] = votingPower[to].add(wAmount);
        vaultCount[to]++;

        _mint(to, wAmount);
        Hakka.safeTransferFrom(msg.sender, address(this), amount);

        emit Stake(to, msg.sender, amount, wAmount, time);
    }


    function unstake(address to, uint256 index, uint256 wAmount) public returns (uint256 amount) {
        vault storage v = vaults[msg.sender][index];

        require(block.timestamp >= v.unlockTime, "locked");
        require(wAmount <= v.wAmount, "exceed locked amount");
        amount = wAmount.mul(v.hakkaAmount).div(v.wAmount);

        v.hakkaAmount = v.hakkaAmount.sub(amount);
        v.wAmount = v.wAmount.sub(wAmount);

        stakedHakka[msg.sender] = stakedHakka[msg.sender].sub(amount);
        votingPower[msg.sender] = votingPower[msg.sender].sub(wAmount);

        _burn(msg.sender, wAmount);
        Hakka.safeTransfer(to, amount);

        emit Unstake(msg.sender, to, amount, wAmount);
    }

    function inCaseTokenGetsStuckPartial(IERC20 _TokenAddress, uint256 _amount) onlyOwner public {
        require(_TokenAddress != Hakka);
        _TokenAddress.safeTransfer(msg.sender, _amount);
    }

}

pragma solidity ^0.5.9;

import "@0x/contracts-utils/contracts/src/LibRichErrors.sol";
import "@0x/contracts-utils/contracts/src/LibSafeMath.sol";
import "../libs/LibStakingRichErrors.sol";
import "../immutable/MixinStorage.sol";
import "../interfaces/IStakingEvents.sol";


contract MixinScheduler is
    IStakingEvents,
    MixinStorage
{
    using LibSafeMath for uint256;





    function getCurrentEpochEarliestEndTimeInSeconds()
        public
        view
        returns (uint256)
    {
        return currentEpochStartTimeInSeconds.safeAdd(epochDurationInSeconds);
    }



    function _initMixinScheduler()
        internal
    {

        _assertSchedulerNotInitialized();


        currentEpochStartTimeInSeconds = block.timestamp;
    }




    function _goToNextEpoch()
        internal
    {


        uint256 currentBlockTimestamp = block.timestamp;


        uint256 epochEndTime = getCurrentEpochEarliestEndTimeInSeconds();

        if (epochEndTime > currentBlockTimestamp) {
            LibRichErrors.rrevert(LibStakingRichErrors.BlockTimestampTooLowError(
                epochEndTime,
                currentBlockTimestamp
            ));
        }


        uint256 nextEpoch = currentEpoch.safeAdd(1);
        currentEpoch = nextEpoch;
        currentEpochStartTimeInSeconds = currentBlockTimestamp;
    }



    function _assertSchedulerNotInitialized()
        internal
        view
    {
        if (currentEpochStartTimeInSeconds != 0) {
            LibRichErrors.rrevert(
                LibStakingRichErrors.InitializationError(
                    LibStakingRichErrors.InitializationErrorCodes.MixinSchedulerAlreadyInitialized
                )
            );
        }
    }
}

pragma solidity 0.5.11;
pragma experimental ABIEncoderV2;

import "../PaymentExitDataModel.sol";
import "../routers/PaymentStandardExitRouterArgs.sol";
import "../../interfaces/IOutputGuardHandler.sol";
import "../../interfaces/ITxFinalizationVerifier.sol";
import "../../models/OutputGuardModel.sol";
import "../../models/TxFinalizationModel.sol";
import "../../registries/OutputGuardHandlerRegistry.sol";
import "../../utils/ExitableTimestamp.sol";
import "../../utils/ExitId.sol";
import "../../utils/OutputId.sol";
import "../../../transactions/PaymentTransactionModel.sol";
import "../../../transactions/outputs/PaymentOutputModel.sol";
import "../../../utils/IsDeposit.sol";
import "../../../utils/UtxoPosLib.sol";
import "../../../framework/PlasmaFramework.sol";
import "../../utils/ExitableTimestamp.sol";

library PaymentStartStandardExit {
    using ExitableTimestamp for ExitableTimestamp.Calculator;
    using IsDeposit for IsDeposit.Predicate;
    using PaymentOutputModel for PaymentOutputModel.Output;
    using UtxoPosLib for UtxoPosLib.UtxoPos;

    struct Controller {
        IExitProcessor exitProcessor;
        PlasmaFramework framework;
        IsDeposit.Predicate isDeposit;
        ExitableTimestamp.Calculator exitableTimestampCalculator;
        OutputGuardHandlerRegistry outputGuardHandlerRegistry;
        ITxFinalizationVerifier txFinalizationVerifier;
        uint256 ethVaultId;
        uint256 erc20VaultId;
    }


    struct StartStandardExitData {
        Controller controller;
        PaymentStandardExitRouterArgs.StartStandardExitArgs args;
        UtxoPosLib.UtxoPos utxoPos;
        PaymentTransactionModel.Transaction outputTx;
        PaymentOutputModel.Output output;
        IOutputGuardHandler outputGuardHandler;
        OutputGuardModel.Data outputGuardData;
        uint160 exitId;
        bool isTxDeposit;
        uint256 txBlockTimeStamp;
        bytes32 outputId;
        TxFinalizationModel.Data finalizationData;
    }

    event ExitStarted(
        address indexed owner,
        uint160 exitId
    );


    function buildController(
        IExitProcessor exitProcessor,
        PlasmaFramework framework,
        OutputGuardHandlerRegistry outputGuardHandlerRegistry,
        ITxFinalizationVerifier txFinalizationVerifier,
        uint256 ethVaultId,
        uint256 erc20VaultId
    )
        public
        view
        returns (Controller memory)
    {
        return Controller({
            exitProcessor: exitProcessor,
            framework: framework,
            isDeposit: IsDeposit.Predicate(framework.CHILD_BLOCK_INTERVAL()),
            exitableTimestampCalculator: ExitableTimestamp.Calculator(framework.minExitPeriod()),
            outputGuardHandlerRegistry: outputGuardHandlerRegistry,
            txFinalizationVerifier: txFinalizationVerifier,
            ethVaultId: ethVaultId,
            erc20VaultId: erc20VaultId
        });
    }


    function run(
        Controller memory self,
        PaymentExitDataModel.StandardExitMap storage exitMap,
        PaymentStandardExitRouterArgs.StartStandardExitArgs memory args
    )
        public
    {
        StartStandardExitData memory data = setupStartStandardExitData(self, args);
        verifyStartStandardExitData(self, data, exitMap);
        saveStandardExitData(data, exitMap);
        enqueueStandardExit(data);

        emit ExitStarted(msg.sender, data.exitId);
    }

    function setupStartStandardExitData(
        Controller memory controller,
        PaymentStandardExitRouterArgs.StartStandardExitArgs memory args
    )
        private
        view
        returns (StartStandardExitData memory)
    {
        UtxoPosLib.UtxoPos memory utxoPos = UtxoPosLib.UtxoPos(args.utxoPos);
        PaymentTransactionModel.Transaction memory outputTx = PaymentTransactionModel.decode(args.rlpOutputTx);
        PaymentOutputModel.Output memory output = outputTx.outputs[utxoPos.outputIndex()];
        bool isTxDeposit = controller.isDeposit.test(utxoPos.blockNum());
        uint160 exitId = ExitId.getStandardExitId(isTxDeposit, args.rlpOutputTx, utxoPos);

        (, uint256 blockTimestamp) = controller.framework.blocks(utxoPos.blockNum());

        OutputGuardModel.Data memory outputGuardData = OutputGuardModel.Data({
            guard: output.outputGuard,
            preimage: args.outputGuardPreimage
        });

        IOutputGuardHandler outputGuardHandler = controller.outputGuardHandlerRegistry.outputGuardHandlers(output.outputType);

        TxFinalizationModel.Data memory finalizationData = TxFinalizationModel.moreVpData(
            controller.framework,
            args.rlpOutputTx,
            utxoPos.txPos(),
            args.outputTxInclusionProof
        );

        bytes32 outputId = isTxDeposit
            ? OutputId.computeDepositOutputId(args.rlpOutputTx, utxoPos.outputIndex(), utxoPos.value)
            : OutputId.computeNormalOutputId(args.rlpOutputTx, utxoPos.outputIndex());

        return StartStandardExitData({
            controller: controller,
            args: args,
            utxoPos: utxoPos,
            outputTx: outputTx,
            output: output,
            outputGuardHandler: outputGuardHandler,
            outputGuardData: outputGuardData,
            exitId: exitId,
            isTxDeposit: isTxDeposit,
            txBlockTimeStamp: blockTimestamp,
            outputId: outputId,
            finalizationData: finalizationData
        });
    }

    function verifyStartStandardExitData(
        Controller memory self,
        StartStandardExitData memory data,
        PaymentExitDataModel.StandardExitMap storage exitMap
    )
        private
        view
    {
        require(data.output.amount > 0, "Should not exit with amount 0");

        require(address(data.outputGuardHandler) != address(0), "Failed to get the output guard handler for the output type");
        require(data.outputGuardHandler.isValid(data.outputGuardData), "Some output guard information is invalid");
        require(data.outputGuardHandler.getExitTarget(data.outputGuardData) == msg.sender, "Only exit target can start an exit");

        require(data.controller.txFinalizationVerifier.isStandardFinalized(data.finalizationData), "The transaction must be standard finalized");
        require(exitMap.exits[data.exitId].exitable == false, "Exit has already started");

        require(self.framework.isOutputSpent(data.outputId) == false, "Output is already spent");
    }

    function saveStandardExitData(
        StartStandardExitData memory data,
        PaymentExitDataModel.StandardExitMap storage exitMap
    )
        private
    {
        exitMap.exits[data.exitId] = PaymentExitDataModel.StandardExit({
            exitable: true,
            utxoPos: uint192(data.utxoPos.value),
            outputId: data.outputId,
            exitTarget: msg.sender,
            amount: data.output.amount,
            bondSize: msg.value
        });
    }

    function enqueueStandardExit(StartStandardExitData memory data) private {

        uint64 exitableAt;
        ExitableTimestamp.Calculator memory exitableTimestampCalculator = data.controller.exitableTimestampCalculator;

        if (data.isTxDeposit){
            exitableAt = exitableTimestampCalculator.calculateDepositTxOutputExitableTimestamp(block.timestamp);
        } else {
            exitableAt = exitableTimestampCalculator.calculateTxExitableTimestamp(block.timestamp, data.txBlockTimeStamp);
        }

        uint256 vaultId;
        if (data.output.token == address(0)) {
            vaultId = data.controller.ethVaultId;
        } else {
            vaultId = data.controller.erc20VaultId;
        }

        data.controller.framework.enqueue(
            vaultId, data.output.token, exitableAt, data.utxoPos.txPos(),
            data.exitId, data.controller.exitProcessor
        );
    }
}

pragma solidity >=0.6.0 <0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";

contract ChimVesting is Ownable, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    address private _erc20TokenAddress;

    uint256 private _releaseTime;


    struct LockPlanData {
        string name;
        uint256 maxPlanTotal;
        uint256 total;
        uint256 withdrawn;
        uint16 startPercent;
        uint32 startDelay;
        uint16 nextPercent;
        uint32 nextDelay;
    }

    uint256 private constant _MAX_PERCENT = 10000; 

    uint256 private constant _MAX_LOCK_PLANS = 15;

    Counters.Counter private _lockPLanIdTracker;

    mapping(uint256 => LockPlanData) private _lockPLans;


    struct AddressLockData {
        uint256 total;
        uint256 withdrawn;
    }

    mapping(address => mapping(uint256 => AddressLockData)) private _addressLocks;


    event ReleaseTimeSet(uint256 time);

    event LockPlanAdded(uint256 lockPlanId);

    event LockPlanUpdated(uint256 lockPlanId);

    event TokensLocked(address indexed account, uint256 lockPlanId, uint256 amount);

    event TokensWithdrawn(address indexed account, uint256 lockPlanId, uint256 amount);


    constructor(address erc20TokenAddress_) {
        require(erc20TokenAddress_ != address(0), "ChimVesting: Invalid erc20 token address");
        _erc20TokenAddress = erc20TokenAddress_;
    }


    function erc20TokenAddress() external view returns (address) {
        return _erc20TokenAddress;
    }


    function maxLockPlans() external pure returns (uint256) {
        return _MAX_LOCK_PLANS;
    }


    function getLockPlanCount() external view returns (uint256) {
        return Counters.current(_lockPLanIdTracker);
    }


    function getLockPlan(uint256 lockPlanId_)
        external
        view
        returns (
            string memory name,
            uint256 maxPlanTotal,
            uint256 total,
            uint256 locked,
            uint256 withdrawn,
            uint16 startPercent,
            uint32 startDelay,
            uint16 nextPercent,
            uint32 nextDelay
        )
    {
        LockPlanData storage lockPlan = _lockPLans[lockPlanId_];
        return (
            lockPlan.name,
            lockPlan.maxPlanTotal,
            lockPlan.total,
            lockPlan.total.sub(lockPlan.withdrawn),
            lockPlan.withdrawn,
            lockPlan.startPercent,
            lockPlan.startDelay,
            lockPlan.nextPercent,
            lockPlan.nextDelay
        );
    }


    function getPlanBalanceOf(
        address account_,
        uint256 lockPlanId_
    )
        external
        view
        returns (
            uint256 total,
            uint256 locked,
            uint256 withdrawn
        )
    {
        AddressLockData storage addressLockData = _addressLocks[account_][lockPlanId_];
        return (
            addressLockData.total,
            addressLockData.total.sub(addressLockData.withdrawn),
            addressLockData.withdrawn
        );
    }


    function getTotalBalanceOf(address account_)
        external
        view
        returns (
            uint256 total,
            uint256 locked,
            uint256 withdrawn
        )
    {
        for (uint256 i = 1; i <= Counters.current(_lockPLanIdTracker); i++) {
            AddressLockData storage addressLockData = _addressLocks[account_][i];
            total = total.add(addressLockData.total);
            withdrawn = withdrawn.add(addressLockData.withdrawn);
        }
        return (
            total,
            total.sub(withdrawn),
            withdrawn
        );
    }


    function releaseTime() external view returns (uint256) {
        return _releaseTime;
    }


    function stats()
        external
        view
        returns (
            uint256 totalBalance,
            uint256 maxPlansTotal,
            uint256 total,
            uint256 totalLocked,
            uint256 totalWithdrawn
        )
    {
        totalBalance = IERC20(_erc20TokenAddress).balanceOf(address(this));
        for (uint256 i = 1; i <= Counters.current(_lockPLanIdTracker); i++) {
            LockPlanData storage lockPlan = _lockPLans[i];
            maxPlansTotal = maxPlansTotal.add(lockPlan.maxPlanTotal);
            total = total.add(lockPlan.total);
            totalWithdrawn = totalWithdrawn.add(lockPlan.withdrawn);
        }
        return (
            totalBalance,
            maxPlansTotal,
            total,
            total.sub(totalWithdrawn),
            totalWithdrawn
        );
    }


    function checkLocks(
        address account_,
        uint256 lockPlanId_
    )
        public
        view
        returns (
            uint256 afterReleaseTime,
            uint256 unlockPercents,
            uint256 nextUnlockTime,
            uint256 total,
            uint256 totalUnlock,
            uint256 withdrawn,
            uint256 pendingUnlock
        )
    {
        if (_releaseTime == 0 || _releaseTime > block.timestamp || lockPlanId_ == 0 || lockPlanId_ > Counters.current(_lockPLanIdTracker)) {
            return (0, 0, 0, 0, 0, 0, 0);
        }

        LockPlanData storage lockPlan = _lockPLans[lockPlanId_];
        afterReleaseTime = block.timestamp.sub(_releaseTime);
        unlockPercents = lockPlan.startPercent;
        for (nextUnlockTime = lockPlan.startDelay; lockPlan.nextPercent > 0 && lockPlan.nextDelay > 0 && nextUnlockTime <= afterReleaseTime && unlockPercents < _MAX_PERCENT; nextUnlockTime = nextUnlockTime.add(lockPlan.nextDelay)) {
            unlockPercents = unlockPercents.add(lockPlan.nextPercent);
        }
        if (unlockPercents >= _MAX_PERCENT) {
            unlockPercents = _MAX_PERCENT;
            nextUnlockTime = 0;
        }

        AddressLockData storage addressLockData = _addressLocks[account_][lockPlanId_];
        total = addressLockData.total;
        totalUnlock = total.mul(unlockPercents).div(_MAX_PERCENT);
        withdrawn = addressLockData.withdrawn;
        if (totalUnlock > withdrawn) {
            pendingUnlock = totalUnlock.sub(withdrawn);
        }

        return (
            afterReleaseTime,
            unlockPercents,
            nextUnlockTime,
            total,
            totalUnlock,
            withdrawn,
            pendingUnlock
        );
    }


    function withdraw(uint256 lockPlanId_) external nonReentrant {
        require(_releaseTime != 0, "ChimVesting: The release time not set");
        require(lockPlanId_ > 0 && lockPlanId_ <= Counters.current(_lockPLanIdTracker), "ChimVesting: LockPlanId not exist");

        (, , , , , , uint256 pendingUnlock) = checkLocks(_msgSender(), lockPlanId_);

        if (pendingUnlock == 0) {
            return;
        }

        LockPlanData storage lockPlan = _lockPLans[lockPlanId_];
        lockPlan.withdrawn = lockPlan.withdrawn.add(pendingUnlock);

        AddressLockData storage addressLockData = _addressLocks[_msgSender()][lockPlanId_];
        addressLockData.withdrawn = addressLockData.withdrawn.add(pendingUnlock);

        IERC20(_erc20TokenAddress).safeTransfer(_msgSender(), pendingUnlock);

        emit TokensWithdrawn(_msgSender(), lockPlanId_, pendingUnlock);
    }


    function setReleaseTime(uint256 time_) external onlyOwner {
        require(_releaseTime == 0, "ChimVesting: The release time can only be set once");

        _releaseTime = time_;

        emit ReleaseTimeSet(time_);
    }


    function addLockPlan(
        string memory name_,
        uint256 maxPlanTotal_,
        uint16 startPercent_,
        uint32 startDelay_,
        uint16 nextPercent_,
        uint32 nextDelay_
    )
        external
        onlyOwner
    {
        require(Counters.current(_lockPLanIdTracker) < _MAX_LOCK_PLANS, "ChimVesting: Max lock plans limit reached");
        require(bytes(name_).length != 0, "ChimVesting: Invalid name");
        require(maxPlanTotal_ != 0, "ChimVesting: Invalid max plan total");
        require(startPercent_ <= _MAX_PERCENT, "ChimVesting: Invalid start percent");
        require(nextPercent_ <= _MAX_PERCENT, "ChimVesting: Invalid next percent");
        require(startPercent_ == _MAX_PERCENT || (nextPercent_ > 0 && nextDelay_ > 0), "ChimVesting: Invalid plan params");

        Counters.increment(_lockPLanIdTracker);
        LockPlanData storage lockPlan = _lockPLans[Counters.current(_lockPLanIdTracker)];
        lockPlan.name = name_;
        lockPlan.maxPlanTotal = maxPlanTotal_;
        lockPlan.startPercent = startPercent_;
        lockPlan.startDelay = startDelay_;
        lockPlan.nextPercent = nextPercent_;
        lockPlan.nextDelay = nextDelay_;

        emit LockPlanAdded(Counters.current(_lockPLanIdTracker));
    }


    function updateLockPlan(
        uint256 lockPlanId_,
        string memory name_,
        uint16 startPercent_,
        uint32 startDelay_,
        uint16 nextPercent_,
        uint32 nextDelay_
    )
        external
        onlyOwner
    {
        require(lockPlanId_ > 0 && lockPlanId_ <= Counters.current(_lockPLanIdTracker), "ChimVesting: LockPlanId not exist");
        require(bytes(name_).length != 0, "ChimVesting: Invalid name");
        require(startPercent_ <= _MAX_PERCENT, "ChimVesting: Invalid start percent");
        require(nextPercent_ <= _MAX_PERCENT, "ChimVesting: Invalid next percent");
        require(startPercent_ == _MAX_PERCENT || (nextPercent_ > 0 && nextDelay_ > 0), "ChimVesting: Invalid plan params");

        LockPlanData storage lockPlan = _lockPLans[lockPlanId_];
        lockPlan.name = name_;
        lockPlan.startPercent = startPercent_;
        lockPlan.startDelay = startDelay_;
        lockPlan.nextPercent = nextPercent_;
        lockPlan.nextDelay = nextDelay_;

        emit LockPlanUpdated(lockPlanId_);
    }


    function lockTokens(
        address account_,
        uint256 amount_,
        uint256 lockPlanId_
    )
        external
        onlyOwner
        nonReentrant
    {
        require(account_ != address(0), "ChimVesting: Invalid address");
        require(lockPlanId_ > 0 && lockPlanId_ <= Counters.current(_lockPLanIdTracker), "ChimVesting: LockPlanId not exist");

        LockPlanData storage lockPlan = _lockPLans[lockPlanId_];
        lockPlan.total = lockPlan.total.add(amount_);
        require(lockPlan.maxPlanTotal >= lockPlan.total, "ChimVesting: Max plan total limit reached");

        AddressLockData storage addressLockData = _addressLocks[account_][lockPlanId_];
        addressLockData.total = addressLockData.total.add(amount_);

        emit TokensLocked(account_, lockPlanId_, amount_);
    }
}

pragma solidity >=0.8.0;
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./OrderBook.sol";
import "./FeeManager.sol";

contract MateCore is OrderBook, FeeManager, ReentrancyGuard {
    using SafeERC20 for IERC20;

    address public immutable mate;

    constructor(
        address _router,
        address _mate,
        address _feeTo
    ) {
        router = IUniswapV2Router02(_router);
        factory = IUniswapV2Factory(router.factory());
        mate = _mate;
        feeTo = _feeTo;
    }

    event OrderExecuted(
        bytes32 indexed orderId,
        address indexed creator,
        address indexed executor,
        uint256 amountOut,
        uint256 timestamp
    );


    function canExecuteOrder(bytes32 _orderId, address[] memory _pathToTokenOut)
        external
        view
        returns (bool success, string memory reason)
    {
        return _canExecuteOrder(_orderId, _pathToTokenOut, new address[](0));
    }


    function canExecuteOrder(
        bytes32 _orderId,
        address[] memory _pathToTokenOut,
        address[] memory _pathToMate
    ) external view returns (bool success, string memory reason) {
        return _canExecuteOrder(_orderId, _pathToTokenOut, _pathToMate);
    }


    function _canExecuteOrder(
        bytes32 _orderId,
        address[] memory _pathToTokenOut,
        address[] memory _pathToMate
    ) internal view returns (bool success, string memory reason) {
        if (paused()) {
            return (false, "Paused");
        }

        Order storage order = orders[_orderId];

        uint256 balance = IERC20(order.tokenIn).balanceOf(order.creator);
        if (balance < order.amountIn) return (false, "Insufficient balance");

        uint256 allowance = IERC20(order.tokenIn).allowance(
            order.creator,
            address(this)
        );
        if (allowance < order.amountIn)
            return (false, "Insufficient allowance");

        if (block.timestamp > order.expiration) return (false, "Expired order");

        if (order.status != Status.Open) return (false, "Invalid status");

        if (
            _pathToTokenOut.length < 1 ||
            _pathToTokenOut[0] != order.tokenIn ||
            _pathToTokenOut[_pathToTokenOut.length - 1] != order.tokenOut
        ) return (false, "Invalid path to output token");

        if (order.tokenIn != mate && _pathToMate.length > 1) {
            if (
                _pathToMate[0] != order.tokenIn ||
                _pathToMate[_pathToMate.length - 1] != mate
            ) return (false, "Invalid path to Mate token");
        }

        (uint256 fee, uint256 executorFee) = calculateFees(order.amountIn);

        uint256 amountInWithFees = order.amountIn - fee - executorFee;

        uint256 amountOutMin = getAmountOutMin(
            amountInWithFees,
            _pathToTokenOut
        );

        if (amountOutMin < order.amountOutMin)
            return (false, "Insufficient output amount");

        return (true, "");
    }


    function executeOrder(bytes32 _orderId, address[] memory _pathToTokenOut)
        external
    {
        _executeOrder(_orderId, _pathToTokenOut, new address[](0));
    }


    function executeOrder(
        bytes32 _orderId,
        address[] memory _pathToTokenOut,
        address[] memory _pathToMate
    ) external {
        _executeOrder(_orderId, _pathToTokenOut, _pathToMate);
    }


    function _executeOrder(
        bytes32 _orderId,
        address[] memory _pathToTokenOut,
        address[] memory _pathToMate
    ) internal nonReentrant whenNotPaused {
        Order storage order = orders[_orderId];

        uint256 balance = IERC20(order.tokenIn).balanceOf(order.creator);
        require(balance >= order.amountIn, "Insufficient balance");

        uint256 allowance = IERC20(order.tokenIn).allowance(
            order.creator,
            address(this)
        );
        require(allowance >= order.amountIn, "Insufficient allowance");

        require(block.timestamp <= order.expiration, "Expired order");

        require(order.status == Status.Open, "Invalid status");

        require(
            _pathToTokenOut.length > 1 &&
                _pathToTokenOut[0] == order.tokenIn &&
                _pathToTokenOut[_pathToTokenOut.length - 1] == order.tokenOut,
            "Invalid path to output token"
        );

        if (order.tokenIn != mate && _pathToMate.length > 1) {
            require(
                _pathToMate[0] == order.tokenIn &&
                    _pathToMate[_pathToMate.length - 1] == mate,
                "Invalid path to Mate token"
            );
        }

        (uint256 fee, uint256 executorFee) = calculateFees(order.amountIn);

        uint256 amountInWithFees = order.amountIn - fee - executorFee;

        uint256 amountOutMin = getAmountOutMin(
            amountInWithFees,
            _pathToTokenOut
        );

        require(
            amountOutMin >= order.amountOutMin,
            "Insufficient output amount"
        );

        order.status = Status.Filled;

        _lockedBalance[order.creator][order.tokenIn] -= order.amountIn;

        IERC20(order.tokenIn).safeTransferFrom(
            order.creator,
            address(this),
            order.amountIn
        );

        uint256 amountOut = _swap(
            _pathToTokenOut,
            amountInWithFees,
            order.amountOutMin,
            order.recipient
        );

        _removeOpenOrder(order.id);

