  address constant internal ESCAPE_HATCH_ENABLER = 0x1df62f291b2e969fb0849d99d9ce41e2f137006e;




  event LogContributionMade(address user, uint256 amount);
  event LogStartOfRound(uint256 currentRound);
  event LogNewLowestBid(uint256 bid,address winnerAddress);
  event LogRoundFundsReleased(address winnerAddress, uint256 amountInWei);
  event LogRoundNoWinner(uint256 currentRound);
  event LogFundsWithdrawal(address user, uint256 amount);
  event LogForepersonSurplusWithdrawal(uint256 amount);



  event LogCannotWithdrawFully(uint256 creditAmount);
  event LogUnsuccessfulBid(address bidder,uint256 bidInWei,uint256 lowestBid);
  event LogEndOfROSCA();


  event LogEscapeHatchEnabled();
  event LogEscapeHatchActivated();
  event LogEmergencyWithdrawalPerformed(uint256 fundsDispersed);






  uint16 internal roundPeriodInDays;
  uint16 internal serviceFeeInThousandths;
  uint16 internal currentRound;  
  address internal foreperson;
  uint128 internal contributionSize;
  uint256 internal startTime;


  bool internal endOfROSCA = false;
  bool internal forepersonSurplusCollected = false;


  uint256 internal totalDiscounts = 0;


  uint256 internal totalFees = 0;


  uint256 internal lowestBid = 0;
  address internal winnerAddress = 0;  

  mapping(address => User) internal members;
  address[] internal membersAddresses;  









  bool internal escapeHatchEnabled = false;
  bool internal escapeHatchActive = false;

  struct User {
    uint256 credit;  
    bool debt; 
    bool paid; 
    bool alive; 
  }




  modifier onlyFromMember {
    if (!members[msg.sender].alive) {
      throw;
    }
    _;
  }

  modifier onlyFromForeperson {
    if (msg.sender != foreperson) {
      throw;
    }
    _;
  }

  modifier onlyFromFeeAddress {
    if (msg.sender != FEE_ADDRESS) {
      throw;
    }
    _;
  }

  modifier roscaNotEnded {
    if (endOfROSCA) {
      throw;
    }
    _;
  }

  modifier roscaEnded {
    if (!endOfROSCA) {
      throw;
    }
    _;
  }

  modifier onlyIfEscapeHatchActive {
    if (!escapeHatchActive) {
      throw;
    }
    _;
  }

  modifier onlyIfEscapeHatchInactive {
    if (escapeHatchActive) {
      throw;
    }
    _;
  }

  modifier onlyFromEscapeHatchEnabler {
    if (msg.sender != ESCAPE_HATCH_ENABLER) {
      throw;
    }
    _;
  }






  function ROSCA (
      uint16 roundPeriodInDays_,
      uint128 contributionSize_,
      uint256 startTime_,
      address[] members_,
      uint16 serviceFeeInThousandths_) {
    if (roundPeriodInDays_ < MIN_ROUND_PERIOD_IN_DAYS || roundPeriodInDays_ > MAX_ROUND_PERIOD_IN_DAYS) {
      throw;
    }
    roundPeriodInDays = roundPeriodInDays_;

    if (contributionSize_ < MIN_CONTRIBUTION_SIZE || contributionSize_ > MAX_CONTRIBUTION_SIZE) {
      throw;
    }
    contributionSize = contributionSize_;

    if (startTime_ < (now + MINIMUM_TIME_BEFORE_ROSCA_START)) {
      throw;
    }
    startTime = startTime_;
    if (serviceFeeInThousandths_ > MAX_FEE_IN_THOUSANDTHS) {
      throw;
    }
    serviceFeeInThousandths = serviceFeeInThousandths_;

    foreperson = msg.sender;
    addMember(msg.sender);

    for (uint16 i = 0; i < members_.length; i++) {
      addMember(members_[i]);
    }
  }

  function addMember(address newMember) internal {
    if (members[newMember].alive) {  
      throw;
    }
    members[newMember] = User({paid: false , credit: 0, alive: true, debt: false});
    membersAddresses.push(newMember);
  }


  function startRound() roscaNotEnded external {
    uint256 roundStartTime = startTime + (uint(currentRound)  * roundPeriodInDays * 1 days);
    if (now < roundStartTime ) {  
      throw;
    }

    if (currentRound != 0) {
      cleanUpPreviousRound();
    }
    if (currentRound < membersAddresses.length) {
      lowestBid = 0;
      winnerAddress = 0;
      currentRound++;
      LogStartOfRound(currentRound);
    } else {
        endOfROSCA = true;
        LogEndOfROSCA();
    }
  }

  function cleanUpPreviousRound() internal {
    address delinquentWinner = 0x0;
    uint256 winnerIndex;
    bool winnerSelectedThroughBid = (winnerAddress != 0);
    uint16 numUnpaidParticipants = uint16(membersAddresses.length) - (currentRound - 1);
    if (winnerAddress == 0) {




      uint256 semi_random = now % numUnpaidParticipants;
      for (uint16 i = 0; i < numUnpaidParticipants; i++) {
        uint256 index = (semi_random + i) % numUnpaidParticipants;
        address candidate = membersAddresses[index];
        if (!members[candidate].paid) {
          winnerIndex = index;
          if (members[candidate].credit + totalDiscounts >= (currentRound * contributionSize)) {

            winnerAddress = candidate;
            break;
          }
          delinquentWinner = candidate;
        }
      }
      if (winnerAddress == 0) {  

        if (delinquentWinner == 0 || members[delinquentWinner].paid) throw;
        winnerAddress = delinquentWinner;

        members[winnerAddress].debt = true;
      }

      lowestBid = contributionSize * membersAddresses.length;
    }



    swapWinner(winnerIndex, winnerSelectedThroughBid, numUnpaidParticipants - 1);

    uint256 currentRoundTotalDiscounts = removeFees(contributionSize * membersAddresses.length - lowestBid);
    totalDiscounts += currentRoundTotalDiscounts / membersAddresses.length;
    members[winnerAddress].credit += removeFees(lowestBid);
    members[winnerAddress].paid = true;
    LogRoundFundsReleased(winnerAddress, lowestBid);
    recalculateTotalFees();
  }


  function recalculateTotalFees() {


    uint256 requiredContributions = currentRound * contributionSize;
    uint256 grossTotalFees = requiredContributions * membersAddresses.length;

    for (uint16 j = 0; j < membersAddresses.length; j++) {
      User member = members[membersAddresses[j]];
      uint256 credit = member.credit;
      uint256 debit = requiredContributions;
      if (member.debt) {


        debit += removeFees(membersAddresses.length * contributionSize);
      }
      if (credit + totalDiscounts < debit) {
        grossTotalFees -= debit - credit - totalDiscounts;
      }
    }

    totalFees = grossTotalFees * serviceFeeInThousandths / 1000;
  }



  function swapWinner(
    uint256 winnerIndex, bool winnerSelectedThroughBid, uint256 indexToSwap) internal {
    if (winnerSelectedThroughBid) {


      for (uint16 i = 0; i <= indexToSwap; i++) {
        if (membersAddresses[i] == winnerAddress) {
          winnerIndex = i;
          break;
        }
      }
    }

    membersAddresses[winnerIndex] = membersAddresses[indexToSwap];
    membersAddresses[indexToSwap] = winnerAddress;
  }


  function removeFees(uint256 amount) internal returns (uint256) {


    return amount * (1000 - serviceFeeInThousandths) / 1000;
  }


  function contribute() payable onlyFromMember roscaNotEnded onlyIfEscapeHatchInactive external {
    User member = members[msg.sender];
    member.credit += msg.value;
    if (member.debt) {




      uint256 requiredContributions = currentRound * contributionSize;
      if (member.credit + totalDiscounts - removeFees(membersAddresses.length * contributionSize) >= requiredContributions) {
          member.debt = false;
      }
    }

    LogContributionMade(msg.sender, msg.value);
  }


  function bid(uint256 bidInWei) onlyFromMember roscaNotEnded onlyIfEscapeHatchInactive external {
    if (members[msg.sender].paid  ||
        currentRound == 0 ||  

        members[msg.sender].credit + totalDiscounts < (currentRound * contributionSize) ||


        bidInWei < contributionSize * membersAddresses.length * MIN_DISTRIBUTION_PERCENT / 100) {
      throw;
    }




    uint256 maxAllowedBid = winnerAddress == 0
        ? contributionSize * membersAddresses.length
        : lowestBid * MAX_NEXT_BID_RATIO / 100;
    if (bidInWei > maxAllowedBid) {



      LogUnsuccessfulBid(msg.sender, bidInWei, lowestBid);
      return;
    }
    lowestBid = bidInWei;
    winnerAddress = msg.sender;
    LogNewLowestBid(lowestBid, winnerAddress);
  }


  function withdraw() onlyFromMember onlyIfEscapeHatchInactive external returns(bool success) {
    if (members[msg.sender].debt && !endOfROSCA) {  
      throw;
    }
    uint256 totalCredit = members[msg.sender].credit + totalDiscounts;

    uint256 totalDebit = members[msg.sender].debt
        ? removeFees(membersAddresses.length * contributionSize)  
        : currentRound * contributionSize;
    if (totalDebit >= totalCredit) {  
        throw;
    }

    uint256 amountToWithdraw = totalCredit - totalDebit;
    uint256 amountAvailable = this.balance - totalFees;

    if (amountAvailable < amountToWithdraw) {

      LogCannotWithdrawFully(amountToWithdraw);
      amountToWithdraw = amountAvailable;
    }
    members[msg.sender].credit -= amountToWithdraw;
    if (!msg.sender.send(amountToWithdraw)) {   


      members[msg.sender].credit += amountToWithdraw;
      return false;
    }
    LogFundsWithdrawal(msg.sender, amountToWithdraw);
    return true;
  }



  function getParticipantBalance(address user) onlyFromMember external constant returns(int256) {
    int256 totalCredit = int256(members[user].credit + totalDiscounts);


    if (members[user].debt && !endOfROSCA) {
        totalCredit -= int256(removeFees(membersAddresses.length * contributionSize));
    }
    int256 totalDebit = int256(currentRound * contributionSize);

    return totalCredit - totalDebit;
  }



  function getContractNetBalance() external constant returns(uint256) {
    return this.balance - totalFees;
  }


  function endOfROSCARetrieveSurplus() onlyFromForeperson roscaEnded external returns (bool) {
    uint256 roscaCollectionTime = startTime + ((membersAddresses.length + 1) * roundPeriodInDays * 1 days);
    if (now < roscaCollectionTime || forepersonSurplusCollected) {
        throw;
    }

    forepersonSurplusCollected = true;
    uint256 amountToCollect = this.balance - totalFees;
    if (!foreperson.send(amountToCollect)) {   


      forepersonSurplusCollected = false;
      return false;
    } else {
      LogForepersonSurplusWithdrawal(amountToCollect);
    }
  }


  function endOfROSCARetrieveFees() onlyFromFeeAddress roscaEnded external returns (bool) {
    uint256 tempTotalFees = totalFees;  
    totalFees = 0;
    if (!FEE_ADDRESS.send(tempTotalFees)) {   


      totalFees = tempTotalFees;
      return false;
    } else {

      LogFundsWithdrawal(FEE_ADDRESS, totalFees);
    }
  }


  function enableEscapeHatch() onlyFromEscapeHatchEnabler external {
    escapeHatchEnabled = true;
    LogEscapeHatchEnabled();
  }


  function activateEscapeHatch() onlyFromForeperson external {
    if (!escapeHatchEnabled) {
      throw;
    }
    escapeHatchActive = true;
    LogEscapeHatchActivated();
  }


  function emergencyWithdrawal() onlyFromForeperson onlyIfEscapeHatchActive {
    LogEmergencyWithdrawalPerformed(this.balance);

    selfdestruct(foreperson);
  }
}

pragma solidity ^0.8.0;

import "./Lender.sol";
import "./Borrower.sol";
import "./PoolToken.sol";
import "../InterestRate/InterestRateModel.sol";

import "../security/Ownable.sol";

import "../Controller/ControllerInterface.sol";
import { IERC20Metadata } from "../ERC20/IERC20.sol";

contract Pool is Ownable, Lendable, Borrowable {
    bool public isInitialized;
    string public name;

    ControllerInterface public controller;
    IERC20Metadata public stableCoin;

    enum Access {
        Public,
        Private
    }
    uint8 public access;

    event AccessChanged(uint8 newAccess);

    function initialize(address _admin, address _stableCoin, string memory _name, uint256 _minDeposit, Access _access) external {
        _initialize(_admin, _stableCoin, _name, _minDeposit, _access);
    }

    function _initialize(address _admin, address _stableCoin, string memory _name, uint256 _minDeposit, Access _access) internal nonReentrant {
        require(!isInitialized, "already initialized");
        isInitialized = true;

        name = _name;
        minDeposit = _minDeposit;
        access = uint8(_access);


        owner = _admin;


        controller = ControllerInterface(msg.sender);


        stableCoin = IERC20Metadata(_stableCoin);

        lpToken = new PoolToken("PoolToken", stableCoin.symbol());
    }

    function changeAccess(Access _access) external onlyOwner {
        access = uint8(_access);
        emit AccessChanged(access);
    }


    function lend(uint256 amount) external returns (uint256) {
        return lendInternal(msg.sender, msg.sender, amount);
    }

    function _lend(uint256 amount, address lender) external returns (uint256) {
        require(msg.sender == address(controller), "wrong address");
        return lendInternal(msg.sender, lender, amount);
    }

    function redeem(uint256 tokens) external returns (uint256) {
        return redeemInternal(msg.sender, 0, tokens);
    }

    function redeemUnderlying(uint256 amount) external returns (uint256) {
        return redeemInternal(msg.sender, amount, 0);
    }

    function _transferTokens(address from, address to, uint256 amount) internal override returns (bool) {
        require(stableCoin.balanceOf(from) >= amount, toString(Error.INSUFFICIENT_FUNDS));
        if (from == address(this)) {
            require(stableCoin.transfer(to, amount), toString(Error.TRANSFER_FAILED));
        } else {
            require(stableCoin.transferFrom(from, to, amount), toString(Error.TRANSFER_FAILED));
        }
        return true;
    }

    function getCash() public override virtual view returns (uint256) {
        return stableCoin.balanceOf(address(this));
    }

    function lendAllowed(address _pool, address _lender, uint256 _amount) internal override returns (uint256) {
        return controller.lendAllowed(_pool, _lender, _amount);
    }

    function redeemAllowed(address _pool, address _redeemer, uint256 _tokenAmount) internal override returns (uint256) {
        return controller.redeemAllowed(_pool, _redeemer, _tokenAmount);
    }


    struct CreditLineLocalVars {
        uint256 allowed;
        uint256 assetValue;
        uint256 borrowCap;
        uint256 interestRate;
        uint256 advanceRate;
        uint256 maturity;
    }
    function createCreditLine(uint256 tokenId) external nonReentrant returns (uint256) {
        CreditLineLocalVars memory vars;
        (
            vars.allowed, 
            vars.assetValue, 
            vars.maturity, 
            vars.interestRate, 
            vars.advanceRate
        ) = controller.createCreditLineAllowed(address(this), msg.sender, tokenId);
        if (vars.allowed != 0) {
            return uint256(Error.C_CREATE_REJECTION);
        }

        vars.borrowCap = vars.assetValue * vars.advanceRate / 100;
        return createCreditLineInternal(msg.sender, tokenId, vars.borrowCap, vars.interestRate, vars.maturity);
    }

    function closeCreditLine(uint256 loanId) external nonReentrant returns (uint256) {
        return closeCreditLineInternal(msg.sender, loanId);
    }

    function redeemAsset(uint256 tokenId) internal override returns (uint256) {
        controller.assetsFactory().markAsRedeemed(tokenId);
        return uint256(Error.NO_ERROR);
    }

    struct UnlockLocalVars {
        MathError mathErr;
        uint256 lockedAsset;
    }
    function unlockAsset(uint256 loanId) external nonReentrant returns (uint256) {
        UnlockLocalVars memory vars;

        (vars.mathErr, vars.lockedAsset) = unlockAssetInternal(msg.sender, loanId);
        ErrorReporter.check((uint256(vars.mathErr)));

        controller.assetsFactory().transferFrom(address(this), msg.sender, vars.lockedAsset);
        return uint256(Error.NO_ERROR);
    }

    function borrow(uint256 loanId, uint256 amount) external returns (uint256) {
        return borrowInternal(loanId, msg.sender, amount);
    }

    function repay(uint256 loanId, uint256 amount) external returns (uint256) {
        return repayInternal(loanId, msg.sender, msg.sender, amount);
    }

    function repayBehalf(address borrower, uint256 loanId, uint256 amount) external returns (uint256) {
        return repayInternal(loanId, msg.sender, borrower, amount);
    }

    function getTotalBorrowBalance() public virtual override(Lendable, Borrowable) view returns (uint256) {
        uint256 total;
        for (uint8 i = 0; i < creditLines.length; i++) {
            total += borrowBalanceSnapshot(i);
        }
        return total;
    }

    struct BorrowIndexLocalVars {
        MathError mathErr;
        uint256 blockNumber;
        uint256 accrualBlockNumber;
        uint256 priorBorrowIndex;
        uint256 newBorrowIndex;
        uint256 borrowRateMantissa;
        uint256 blockDelta;
        Exp interestFactor;
    }
    function getBorrowIndex(uint256 loanId) public override view returns (uint256) {
        CreditLine storage creditLine = creditLines[loanId];
        BorrowIndexLocalVars memory vars;

        vars.accrualBlockNumber = creditLine.accrualBlockNumber;
        vars.priorBorrowIndex = creditLine.borrowIndex;
        vars.blockNumber = getBlockNumber();


        if (vars.accrualBlockNumber == vars.blockNumber || vars.accrualBlockNumber == 0) {
            return vars.priorBorrowIndex;
        }

        vars.borrowRateMantissa = controller.interestRateModel().getBorrowRate(creditLine.interestRate);
        (vars.mathErr, vars.blockDelta) = subUInt(vars.blockNumber, vars.accrualBlockNumber);
        ErrorReporter.check((uint256(vars.mathErr)));

        (vars.mathErr, vars.interestFactor) = mulScalar(Exp({mantissa: vars.borrowRateMantissa}), vars.blockDelta);
        ErrorReporter.check((uint256(vars.mathErr)));

        (vars.mathErr, vars.newBorrowIndex) = mulScalarTruncateAddUInt(vars.interestFactor, vars.priorBorrowIndex, vars.priorBorrowIndex);
        ErrorReporter.check((uint256(vars.mathErr)));

        return vars.newBorrowIndex;
    }

    struct PenaltyIndexLocalVars {
        MathError mathErr;
        uint256 fee;
        uint256 principal;
        uint256 daysDelta;
        uint256 interestBlocksPerYear;
        uint256 penaltyIndex;
        uint256 penaltyAmount;
        uint256 accrualTimestamp;
        uint256 timestamp;
    }
    function getPenaltyIndexAndFee(uint256 loanId) public override view returns(uint256, uint256) {
        PenaltyInfo storage _penaltyInfo = penaltyInfo[loanId];

        if (creditLines[loanId].isClosed) {
            return (0, 0);
        }

        PenaltyIndexLocalVars memory vars;
        InterestRateModel.GracePeriod[] memory _gracePeriod;

        uint256 day = 24 * 60 * 60;
        vars.principal = creditLines[loanId].principal;
        vars.accrualTimestamp = _penaltyInfo.timestamp;
        vars.penaltyIndex = _penaltyInfo.index;
        vars.timestamp = getBlockTimestamp();

        (_gracePeriod, vars.interestBlocksPerYear) = controller.interestRateModel().getGracePeriodSnapshot();
        for(uint8 i=0; i < _gracePeriod.length; i++) {
            uint256 _start = _gracePeriod[i].start * day + _penaltyInfo.maturity;
            uint256 _end = _gracePeriod[i].end * day + _penaltyInfo.maturity;

            if (vars.timestamp >= _start) {
                if(vars.timestamp > _end) {
                    vars.daysDelta = _calculateDaysDelta(_end, vars.accrualTimestamp, _start, day);
                } else {
                    vars.daysDelta = _calculateDaysDelta(vars.timestamp, vars.accrualTimestamp, _start, day);
                }

                vars.penaltyIndex = calculatePenaltyIndexPerPeriod(_gracePeriod[i].fee, vars.interestBlocksPerYear, vars.daysDelta, vars.penaltyIndex);
                (vars.mathErr, vars.fee) = mulScalarTruncateAddUInt(Exp({mantissa: vars.penaltyIndex }), vars.principal, vars.fee);
                ErrorReporter.check((uint256(vars.mathErr)));
            }
        }

        if (vars.fee > 0) {
            (vars.mathErr, vars.penaltyAmount) = subUInt(vars.fee, vars.principal);
            ErrorReporter.check((uint256(vars.mathErr)));
        }
        return (vars.penaltyIndex, vars.penaltyAmount);
    }

    function _calculateDaysDelta(uint256 timestamp, uint256 acrrualTimestamp, uint256 _start, uint256 day) internal pure returns (uint256) {
        MathError mathErr;
        uint256 daysDelta;
        if (acrrualTimestamp > _start) {
            (mathErr, daysDelta) = subThenDivUInt(timestamp, acrrualTimestamp, day);
            ErrorReporter.check((uint256(mathErr)));
        } else {
            (mathErr, daysDelta) = subThenDivUInt(timestamp, _start, day);
            ErrorReporter.check((uint256(mathErr)));
        }
        return daysDelta;
    }

    function calculatePenaltyIndexPerPeriod(uint fee, uint256 blockPerYear, uint256 daysDelta, uint256 currentPenaltyIndex) internal pure returns (uint256) {
        Exp memory simpleInterestFactor;
        MathError mathErr;
        uint256 penaltyIndex;

        (mathErr, simpleInterestFactor) = mulScalar(Exp({mantissa: fee / blockPerYear }), daysDelta);
        ErrorReporter.check((uint256(mathErr)));

        (mathErr, penaltyIndex) = mulScalarTruncateAddUInt(simpleInterestFactor, currentPenaltyIndex, currentPenaltyIndex);
        ErrorReporter.check((uint256(mathErr)));

        return penaltyIndex;
    }

    struct TransferLocalVars {
        MathError mathError;
        uint256 feesMantissa;
        uint256 feesAmount;
        uint256 amountWithoutFees;
    }
    function _transferTokensOnBorrow(address from, address to, uint256 amount) internal override returns (bool) {
        require(stableCoin.balanceOf(from) >= amount, toString(Error.INSUFFICIENT_FUNDS));

        TransferLocalVars memory vars;

        vars.feesMantissa = controller.provisionPool().getFeesPercent();

        (vars.mathError, vars.feesAmount) = mulScalarTruncate(Exp({ mantissa: vars.feesMantissa }), amount);
        ErrorReporter.check(uint256(vars.mathError));

        (vars.mathError, vars.amountWithoutFees) = subUInt(amount, vars.feesAmount);
        ErrorReporter.check(uint256(vars.mathError));

        require(stableCoin.transfer(to, vars.amountWithoutFees), toString(Error.TRANSFER_FAILED));
        require(stableCoin.transfer(controller.provisionPool.address, vars.feesAmount), toString(Error.LPP_TRANSFER_FAILED));
        return true;
    }

    function _transferTokensOnRepay(address from, address to, uint256 amount, uint256 penaltyAmount) internal override returns (bool) {
        require(_transferTokens(from, to, amount), toString(Error.TRANSFER_FAILED));

        if (penaltyAmount > 0) {
            return _transferTokens(to, controller.provisionPool.address, penaltyAmount);
        }
        return true;
    }

    function borrowAllowed(address _pool, address _lender, uint256 _amount) internal override returns (uint256) {
        return controller.borrowAllowed(_pool, _lender, _amount);
    }

    function repayAllowed(address _pool, address _payer, address _borrower, uint256 _amount) internal override returns (uint256) {
        return controller.repayAllowed(_pool, _payer, _borrower, _amount);
    }

    function getBlockNumber() public virtual override view returns(uint256) {
        return block.number;
    }

    function getBlockTimestamp() public virtual override view returns(uint256) {

        return block.timestamp;
    }
}

pragma solidity 0.8.4;

import { IERC20 } from "../ERC20/IERC20.sol";
import "../security/ReentrancyGuard.sol";
import "../utils/Counters.sol";
import "../utils/NonZeroAddressGuard.sol";
import "../security/Ownable.sol";




contract Vesting is ReentrancyGuard, Ownable, NonZeroAddressGuard {
    using Counters for Counters.Counter;


    Counters.Counter private _entryIds;


    IERC20 public token;

    struct Entry {
        uint256 amount;
        uint256 start;
        uint256 end;
        uint256 cliff;
        uint256 lastUpdated;
        uint256 claimed;
        address recipient;
        bool isFireable;
        bool isFired;
    }


    mapping(uint256 => Entry) public entries;


    mapping(address => uint256[]) public entryIdsByRecipient;


    bool private _initialized;

    event EntryCreated(uint256 indexed entryId, address recipient, uint256 amount, uint256 start, uint256 end, uint256 cliff);
    event EntryFired(uint256 indexed entryId);
    event Claimed(address indexed recipient, uint256 amount);


    function initialize(address owner_, IERC20 token_) external nonZeroAddress(owner_) nonZeroAddress(address(token_)) {
        require(!_initialized, "Already initialized");
        owner = owner_;
        token = token_;

        _initialized = true;
    }

    struct EntryVars {
        address recipient;
        uint256 amount;
        uint256 start;
        uint256 end;
        uint256 cliff;
        uint256 unlocked;
        bool isFireable;
    }


    function createEntry(EntryVars calldata entry) external onlyOwner nonReentrant returns (bool){
        return _createEntry(entry);
    }


    function fireEntry(uint256 entryId) external onlyOwner returns (bool){
        return _fireEntry(entryId);
    }


    function createEntries(EntryVars[] calldata _entries) external onlyOwner nonReentrant returns (bool){
        require(_entries.length  > 0, "empty data");
        require(_entries.length  <= 80, "exceed max length");

        for(uint8 i=0; i < _entries.length; i++) {
            _createEntry(_entries[i]);
        }
        return true;
    }


    function claim() external nonReentrant  {
        uint256 totalAmount;
        for(uint8 i=0; i < entryIdsByRecipient[msg.sender].length; i++) {
            totalAmount += _claim(entryIdsByRecipient[msg.sender][i]);
        }
        if (totalAmount > 0) {
            emit Claimed(msg.sender, totalAmount);
            assert(token.transfer(msg.sender, totalAmount));
        }
    }


    function withdraw(address destination) external onlyOwner nonZeroAddress(destination) returns (bool) {
        require(token.transfer(destination, this.balanceOf()), "transfer failed");
        return true;
    }


    function balanceOf() external view returns (uint256) {
        return token.balanceOf(address(this));
    }


    function balanceOf(uint256 entryId) external view returns (uint256 amount) {
        return _balanceOf(entryId);
    }


    function balanceOf(address account) external view returns (uint256 amount) {
        for(uint8 i=0; i < entryIdsByRecipient[account].length; i++) {
            amount += _balanceOf(entryIdsByRecipient[account][i]);
        }
        return amount;
    }



    struct Snapshot {
        uint256 entryId;
        uint256 amount;
        uint256 start;
        uint256 end;
        uint256 cliff;
        uint256 claimed;
        uint256 available;
        bool isFired;
    }


    function getSnapshot(address account) external nonZeroAddress(account) view returns(Snapshot[] memory) {
        Snapshot[] memory snapshot = new Snapshot[](entryIdsByRecipient[account].length);

        for(uint8 i=0; i < entryIdsByRecipient[account].length; i++) {
            Entry memory entry = entries[entryIdsByRecipient[account][i]];
            snapshot[i] = Snapshot({
                entryId: entryIdsByRecipient[account][i],
                amount: entry.amount,
                start: entry.start,
                end: entry.end,
                cliff: entry.cliff,
                claimed: entry.claimed,
                available: _balanceOf(entryIdsByRecipient[account][i]),
                isFired: entry.isFired
            });
        }
        return snapshot;
    }


    function lockedOf(uint256 entryId) external view returns (uint256 amount) {
        return _lockedOf(entryId);
    }


    function lockedOf(address account) external view returns (uint256 amount) {
        for(uint8 i=0; i < entryIdsByRecipient[account].length; i++) {
            amount += _lockedOf(entryIdsByRecipient[account][i]);
        }
        return amount;
    }

    function getBlockTimestamp() public virtual view returns (uint256) {
        return block.timestamp;
    }

    function _balanceOf(uint256 _entryId) internal view returns (uint256) {
        Entry storage entry = entries[_entryId];

        if (entry.amount == 0) { 
            return 0;
        }

        uint256 currentTimestamp = getBlockTimestamp();
        if (currentTimestamp <= entry.start + entry.cliff) {
            return 0;
        }

        if (currentTimestamp > entry.end || entry.isFired) {
            return entry.amount - entry.claimed;
        }

        uint256 vested = entry.amount * (currentTimestamp - entry.lastUpdated) / (entry.end - entry.start);
        return vested;
    }

    function _lockedOf(uint256 _entryId) internal view returns (uint256) {
        Entry storage entry = entries[_entryId];
        if (entry.amount == 0) { 
            return 0;
        }
        return entry.amount - entry.claimed;
    }

    function _createEntry(EntryVars memory entry) internal returns (bool success) {
        address recipient = entry.recipient;
        require(recipient != address(0), "recipient cannot be the zero address");


        require(entry.amount > 0, "amount must be greater than zero");
        require(entry.unlocked <= entry.amount, "unlocked cannot be greater than amount");
        require(entry.end >= entry.start, "End time must be after start time");
        require(entry.end > entry.start + entry.cliff, "cliff must be less than end");

        uint256 currentTimestamp = getBlockTimestamp();
        require(entry.start >= currentTimestamp, "Start time must be in the future");

        if (entry.unlocked > 0) {
            assert(token.transfer(recipient, entry.unlocked));
        }

        uint256 currentEntryId = _entryIds.current();
        if (entry.unlocked < entry.amount) {
            entries[currentEntryId] = Entry({
                recipient: recipient,
                amount: entry.amount - entry.unlocked,
                start: entry.start,
                lastUpdated: entry.start,
                end: entry.end,
                cliff: entry.cliff,
                claimed: 0,
                isFireable: entry.isFireable,
                isFired: false
            });
            entryIdsByRecipient[recipient].push(currentEntryId);

            emit EntryCreated(currentEntryId, recipient, entry.amount - entry.unlocked, entry.start, entry.end, entry.cliff);
            _entryIds.increment();
        }

        return true;
    }

    function _fireEntry(uint256 _entryId) internal returns (bool success) {
        Entry storage entry = entries[_entryId];
        require(entry.amount > 0, "entry not exists");
        require(entry.isFireable, "entry not fireable");

        entry.amount = _balanceOf(_entryId);
        entry.isFired = true;

        emit EntryFired(_entryId);
        return true;
    }

    function _claim(uint256 _entryId) internal returns (uint256 amount) {
        Entry storage entry = entries[_entryId];

        uint256 amountToClaim = _balanceOf(_entryId);
        if (amountToClaim > 0) {
            uint256 currentTimestamp = getBlockTimestamp();

            entry.lastUpdated = currentTimestamp;
            entry.claimed += amountToClaim;


            require(entry.amount >= entry.claimed, "claim exceed vested amount");
        }

        return amountToClaim;
    }
}

