        uint256 amount
    ) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        unchecked {
            _approve(sender, _msgSender(), currentAllowance - amount);
        }

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(currentAllowance >= subtractedValue, "ERC20: decreased allowance below zero");
        unchecked {
            _approve(_msgSender(), spender, currentAllowance - subtractedValue);
        }

        return true;
    }


    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");

        _beforeTokenTransfer(sender, recipient, amount);

        uint256 senderBalance = _balances[sender];
        require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
        unchecked {
            _balances[sender] = senderBalance - amount;
        }
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);

        _afterTokenTransfer(sender, recipient, amount);
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);

        _afterTokenTransfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "ERC20: burn amount exceeds balance");
        unchecked {
            _balances[account] = accountBalance - amount;
        }
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);

        _afterTokenTransfer(account, address(0), amount);
    }


    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }


    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}


    function _afterTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}
}





pragma solidity ^0.8.7;





contract Bollystake is ERC20("sBOLLY Staked Bollycoin", "sBOLLY"),Ownable{
    using SafeMath for uint256;

    IERC20 public immutable BOLLY;

    constructor(IERC20 _BOLLY) {
        require(address(_BOLLY) != address(0), "_BOLLY is a zero address");
        BOLLY = _BOLLY;
    }
    uint256 private constant _TIMELOCK_30 = 3 minutes;
    uint256 private constant _TIMELOCK_60 = 6 minutes;
    uint256 private constant _TIMELOCK_90 = 9 minutes;
    uint256 private constant _TIMELOCK_180 = 18 minutes;
    uint256 private constant _TIMELOCK_365 = 36 minutes;
    uint256 private constant _TIMELOCK_540 = 54 minutes;
    uint256 private constant _TIMELOCK_730 = 73 minutes;



     struct locked{
        uint256 expire;
        uint256 locked_amount;
     }
     mapping(address => locked) users;
     mapping(address => locked[7]) user_stake;
      address[] internal stakeholders;

   function isStakeholder(address _address)
       public
       view
       returns(bool, uint256)
   {
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           if (_address == stakeholders[s]) return (true, s);
       }
       return (false, 0);
   }


   function addStakeholder(address _stakeholder)
       private
   {
       (bool _isStakeholder, ) = isStakeholder(_stakeholder);
       if(!_isStakeholder) stakeholders.push(_stakeholder);
   }


   function removeStakeholder(address _stakeholder)
       private
   {
       (bool _isStakeholder, uint256 s) = isStakeholder(_stakeholder);
       if(_isStakeholder){
           stakeholders[s] = stakeholders[stakeholders.length - 1];
           stakeholders.pop();
       }
   }

   mapping(address => uint256) internal stakes;


   function stakeOf(address _stakeholder)
       public
       view
       returns(uint256)
   {
       return stakes[_stakeholder];
   }


   function totalStakes()
       external
       view 
       returns(uint256)
   {
       uint256 _totalStakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _totalStakes = _totalStakes.add(stakes[stakeholders[s]]);
       }
       return _totalStakes;
   }

   function total_eligible_Stakes()
       public
       view
       returns(uint256)
   {
       uint256 _totaleligibleStakes = 0;
       uint256 _usereligiblestakes = 0;
       uint256 _expired_stakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _expired_stakes = expired_stakes(stakeholders[s]);
           _usereligiblestakes = stakes[stakeholders[s]].sub(_expired_stakes);
           _totaleligibleStakes = _totaleligibleStakes.add(_usereligiblestakes);
       }
       return _totaleligibleStakes;
   }

   function Eligible_stakes() external view returns (address [] memory,uint256 [] memory)
   {
       uint256 [] memory eligible_stakes = new uint256[](stakeholders.length);
       address [] memory user_address = new address[](stakeholders.length);
       uint256 _expired_stakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _expired_stakes = expired_stakes(stakeholders[s]);
           eligible_stakes[s] = stakes[stakeholders[s]].sub(_expired_stakes);
           user_address[s]= stakeholders[s];
       }
      return (user_address,eligible_stakes);
   }

    function get_all_user_stakes() external view returns (address [] memory, uint256 [7][] memory,uint256 [7][] memory)
   {
       uint256[7][] memory all_user_stakes = new uint256[7][](stakeholders.length);
       uint256[7][] memory all_user_eligible_stakes = new uint256[7][](stakeholders.length);
       address [] memory user_address = new address[](stakeholders.length);
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           all_user_stakes[s] = [user_stake[stakeholders[s]][0].locked_amount,user_stake[stakeholders[s]][1].locked_amount,user_stake[stakeholders[s]][2].locked_amount,user_stake[stakeholders[s]][3].locked_amount,user_stake[stakeholders[s]][4].locked_amount,user_stake[stakeholders[s]][5].locked_amount,user_stake[stakeholders[s]][6].locked_amount];
           user_address[s]= stakeholders[s];
           for(uint k=0;k<7;k+=1){
               if(user_stake[stakeholders[s]][k].expire > block.timestamp ) {
                 all_user_eligible_stakes[s][k]=user_stake[stakeholders[s]][k].locked_amount;
               } else {
                 all_user_eligible_stakes[s][k]=0;  
               }
           }
       }
      return (user_address,all_user_stakes,all_user_eligible_stakes);
   }

   function expired_stakes (address _stakeholder) public view returns(uint256)
   {
       locked[7] storage user_stake_info = user_stake[_stakeholder];
        uint256 expired_amount=0;
        for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 expired_amount = expired_amount.add(user_stake_info[s].locked_amount);
             }
        }
        return expired_amount;
   }    


    function enter_stake(uint256 _amount ,uint256 _days) external {

        require(_days ==30||_days==60||_days==90||_days==180||_days==365||_days==540||_days==730,"number of days should be among 30,60,90,180,365,540,730");
        if(stakes[msg.sender] == 0) addStakeholder(msg.sender);
       stakes[msg.sender] = stakes[msg.sender].add(_amount);

        locked[7] storage user_stake_info = user_stake[msg.sender];
        if (_days ==30) {
        user_stake_info[0].expire = block.timestamp + _TIMELOCK_30;
        user_stake_info[0].locked_amount = user_stake_info[0].locked_amount.add(_amount);
        } else if (_days ==60) {
        user_stake_info[1].expire = block.timestamp + _TIMELOCK_60;
        user_stake_info[1].locked_amount = user_stake_info[1].locked_amount.add(_amount);
        } else if (_days ==90) {
        user_stake_info[2].expire = block.timestamp + _TIMELOCK_90;
        user_stake_info[2].locked_amount = user_stake_info[2].locked_amount.add(_amount);
        } else if (_days ==180) {
        user_stake_info[3].expire = block.timestamp + _TIMELOCK_180;
        user_stake_info[3].locked_amount = user_stake_info[3].locked_amount.add(_amount);
        } else if (_days ==365) {
        user_stake_info[4].expire = block.timestamp + _TIMELOCK_365;
        user_stake_info[4].locked_amount = user_stake_info[4].locked_amount.add(_amount);
        } else if (_days ==540) {
        user_stake_info[5].expire = block.timestamp + _TIMELOCK_540;
        user_stake_info[5].locked_amount = user_stake_info[5].locked_amount.add(_amount);
        } else if (_days ==730) {
        user_stake_info[6].expire = block.timestamp + _TIMELOCK_730;
        user_stake_info[6].locked_amount = user_stake_info[6].locked_amount.add(_amount);
        }
        BOLLY.transferFrom(msg.sender, address(this), _amount);
        _mint(msg.sender, _amount);
        emit _enter_stake(_amount,msg.sender,_days);
    }

    function relock_stake(uint256 _days) external {
        (bool _isStakeholder, ) = isStakeholder(msg.sender);
        require(_isStakeholder==true, "only current stakeholders can relock stake");
        require(_days ==30||_days==60||_days==90||_days==180||_days==365||_days==540||_days==730,"number of days should be among 30,60,90,180,365,540,730");
        locked[7] storage user_stake_info = user_stake[msg.sender];
        uint256 expired_amount = expired_stakes(msg.sender);
        for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 user_stake_info[s].locked_amount = 0;
             }
        }    
        if (_days ==30) {    
        user_stake_info[0].expire = block.timestamp + _TIMELOCK_30;
        user_stake_info[0].locked_amount = expired_amount;
        } else if (_days ==60) {
        user_stake_info[1].expire = block.timestamp + _TIMELOCK_60;
        user_stake_info[1].locked_amount = expired_amount;
        } else if (_days ==90) {
        user_stake_info[2].expire = block.timestamp + _TIMELOCK_90;
        user_stake_info[2].locked_amount = expired_amount;
        } else if (_days ==180) {
        user_stake_info[3].expire = block.timestamp + _TIMELOCK_180;
        user_stake_info[3].locked_amount = expired_amount;
        } else if (_days ==365) {
        user_stake_info[4].expire = block.timestamp + _TIMELOCK_365;
        user_stake_info[4].locked_amount = expired_amount;
        } else if (_days ==540) {
        user_stake_info[5].expire = block.timestamp + _TIMELOCK_540;
        user_stake_info[5].locked_amount = expired_amount;
        } else if (_days ==730) {
        user_stake_info[6].expire = block.timestamp + _TIMELOCK_730;
        user_stake_info[6].locked_amount = expired_amount;
        }
        emit _relock_stake(msg.sender,_days,expired_amount);
    }



    function remove_stake() external {
        locked[7] storage user_stake_info = user_stake[msg.sender];
        uint256 expired_amount = expired_stakes(msg.sender);
        require( (expired_amount>0) ,"Please wait until some stakes are expired");
        _burn(msg.sender,expired_amount );
         for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 user_stake_info[s].locked_amount = 0;
             }
        }
         stakes[msg.sender] = stakes[msg.sender].sub(expired_amount);
       if(stakes[msg.sender] == 0) removeStakeholder(msg.sender);
        BOLLY.transfer(msg.sender, expired_amount);
        emit _remove_stake(expired_amount,msg.sender);
    }

    function emergency_remove_stake(address _user) external onlyOwner{
        locked[7] storage user_stake_info = user_stake[_user];
        uint256 locked_amount = stakeOf(_user);
        require( (locked_amount>0) ,"Please wait until some stakes are expired");
        _burn(_user,locked_amount);
         for (uint256 s = 0; s < 7; s += 1){
                 user_stake_info[s].locked_amount = 0;
        }
         stakes[_user] = stakes[_user].sub(locked_amount);
       if(stakes[_user] == 0) removeStakeholder(_user);
        BOLLY.transfer(_user, locked_amount);
        emit _remove_stake(locked_amount,_user);
    }


    event _set_owner(address _owner, address _from) ;    
    event _enter_stake(uint256 _amount, address _stake_from, uint256 _days);
    event _relock_stake(address stake_from,uint256 _days, uint256 _expired_amount);
    event _remove_stake(uint256 _amount,address _stake_to); 
}

pragma solidity 0.5.0;

contract ReentrancyGuard {











    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor () internal {
        _status = _NOT_ENTERED;
    }


    modifier nonReentrant() {

        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");


        _status = _ENTERED;

        _;



        _status = _NOT_ENTERED;
    }
}

library Math {
    function max(uint256 a, uint256 b) internal pure returns (uint256) {
        return a >= b ? a : b;
    }

    function min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }

    function average(uint256 a, uint256 b) internal pure returns (uint256) {
        return (a / 2) + (b / 2) + (((a % 2) + (b % 2)) / 2);
    }
}

library SafeMath {
    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        require(c >= a, "SafeMath: addition overflow");

        return c;
    }

    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        return sub(a, b, "SafeMath: subtraction overflow");
    }

    function sub(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b <= a, errorMessage);
        uint256 c = a - b;

        return c;
    }

    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        if (a == 0) {
            return 0;
        }

        uint256 c = a * b;
        require(c / a == b, "SafeMath: multiplication overflow");

        return c;
    }

    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        return div(a, b, "SafeMath: division by zero");
    }

    function div(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b > 0, errorMessage);
        uint256 c = a / b;

        return c;
    }

    function mod(uint256 a, uint256 b) internal pure returns (uint256) {
        return mod(a, b, "SafeMath: modulo by zero");
    }

    function mod(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b != 0, errorMessage);
        return a % b;
    }
}

contract Context {
    constructor() internal {}

    function _msgSender() internal view returns (address payable) {
        return msg.sender;
    }

    function _msgData() internal view returns (bytes memory) {
        this;
        return msg.data;
    }
}

contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(
        address indexed previousOwner,
        address indexed newOwner
    );

    constructor() internal {
        _owner = _msgSender();
        emit OwnershipTransferred(address(0), _owner);
    }

    function owner() public view returns (address) {
        return _owner;
    }

    modifier onlyOwner() {
        require(isOwner(), "Ownable: caller is not the owner");
        _;
    }

    function isOwner() public view returns (bool) {
        return _msgSender() == _owner;
    }

    function renounceOwnership() public onlyOwner {
        emit OwnershipTransferred(_owner, address(0));
        _owner = address(0);
    }

    function transferOwnership(address newOwner) public onlyOwner {
        _transferOwnership(newOwner);
    }

    function _transferOwnership(address newOwner) internal {
        require(
            newOwner != address(0),
            "Ownable: new owner is the zero address"
        );
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

interface IERC20 {
    function totalSupply() external view returns (uint256);

    function balanceOf(address account) external view returns (uint256);

    function transfer(address recipient, uint256 amount)
        external
        returns (bool);

    function allowance(address owner, address spender)
        external
        view
        returns (uint256);

    function approve(address spender, uint256 amount) external returns (bool);

    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(
        address indexed owner,
        address indexed spender,
        uint256 value
    );
}

library Address {
    function isContract(address account) internal view returns (bool) {
        bytes32 codehash;
        bytes32 accountHash =
            0xc5d2460186f7233c927e7db2dcc703c0e500b653ca82273b7bfad8045d85a470;

        assembly {
            codehash := extcodehash(account)
        }
        return (codehash != 0x0 && codehash != accountHash);
    }

    function toPayable(address account)
        internal
        pure
        returns (address payable)
    {
        return address(uint160(account));
    }

    function sendValue(address payable recipient, uint256 amount) internal {
        require(
            address(this).balance >= amount,
            "Address: insufficient balance"
        );

        (bool success, ) = recipient.call.value(amount)("");
        require(
            success,
            "Address: unable to send value, recipient may have reverted"
        );
    }
}

library SafeERC20 {
    using SafeMath for uint256;
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        callOptionalReturn(
            token,
            abi.encodeWithSelector(token.transfer.selector, to, value)
        );
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        callOptionalReturn(
            token,
            abi.encodeWithSelector(token.transferFrom.selector, from, to, value)
        );
    }

    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        callOptionalReturn(
            token,
            abi.encodeWithSelector(token.approve.selector, spender, value)
        );
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance =
            token.allowance(address(this), spender).add(value);
        callOptionalReturn(
            token,
            abi.encodeWithSelector(
                token.approve.selector,
                spender,
                newAllowance
            )
        );
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance =
            token.allowance(address(this), spender).sub(
                value,
                "SafeERC20: decreased allowance below zero"
            );
        callOptionalReturn(
            token,
            abi.encodeWithSelector(
                token.approve.selector,
                spender,
                newAllowance
            )
        );
    }

    function callOptionalReturn(IERC20 token, bytes memory data) private {
        require(address(token).isContract(), "SafeERC20: call to non-contract");

        (bool success, bytes memory returndata) = address(token).call(data);
        require(success, "SafeERC20: low-level call failed");

        if (returndata.length > 0) {


            require(
                abi.decode(returndata, (bool)),
                "SafeERC20: ERC20 operation did not succeed"
            );
        }
    }
}

contract LPTokenWrapper is Ownable, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    IERC20 public BSKTASREWARD = IERC20(0x4Bec13aB192280763A201a30ca093a3d0a15b3DC);  

    uint256 private _totalSupply;
    mapping(address => uint256) private _balances;

    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }

    function balanceOf(address account) public view returns (uint256) {
        return _balances[account];
    }

    function stake(uint256 amount) nonReentrant public  {
        _totalSupply = _totalSupply.add(amount);
        _balances[_msgSender()] = _balances[_msgSender()].add(amount);
        BSKTASREWARD.safeTransferFrom(_msgSender(), address(this), amount);
    }

    function withdraw(uint256 amount) nonReentrant public {
        _totalSupply = _totalSupply.sub(amount);
        _balances[_msgSender()] = _balances[_msgSender()].sub(amount);
        BSKTASREWARD.safeTransfer(_msgSender(), amount);
    }
}

contract BsktEthLPPool is LPTokenWrapper {

    IERC20 public STAKEBSKT = IERC20(0x3d3c60970D3369e48f79664787433fc0d2B7C44b); 

    uint256 public constant duration = 100 days;     
    uint256 public starttime = 0;                    
    uint256 public periodFinish = 0;
    uint256 public rewardRate = 0;
    uint256 public lastUpdateTime;
    uint256 public rewardPerTokenStored;

    bool firstNotify;

    mapping(address => uint256) public userRewardPerTokenPaid;
    mapping(address => uint256) public rewards;
    mapping(address => bool) public minimumBsktStakingEntry;

    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event Rewarded(address indexed from, address indexed to, uint256 value);

    modifier checkStart() {
        require(
            block.timestamp >= starttime,
            "Error:Pool not started yet."
        );
        _;
    }

    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = lastTimeRewardApplicable();
        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerTokenPaid[account] = rewardPerTokenStored;
        }
        _;
    }

    function lastTimeRewardApplicable() public view returns (uint256) {
        return Math.min(block.timestamp, periodFinish);
    }

    function rewardPerToken() public view returns (uint256) {
        if (totalSupply() == 0) {
            return rewardPerTokenStored;
        }
        return
            rewardPerTokenStored.add(
                lastTimeRewardApplicable()
                    .sub(lastUpdateTime)
                    .mul(rewardRate)
                    .mul(1e18)
                    .div(totalSupply())
            );
    }

    function earned(address account) public view returns (uint256) {
        return balanceOf(account)
                .mul(rewardPerToken().sub(userRewardPerTokenPaid[account]))
                .div(1e18)
                .add(rewards[account]);
    }

    function stake(uint256 amount) public updateReward(_msgSender()) checkStart {
        require(amount > 0, "Cannot stake 0");
        super.stake(amount);

        emit Staked(_msgSender(), amount);
    }

    function withdraw(uint256 amount)
        public
        updateReward(_msgSender())
    {
        require(amount > 0, "Cannot withdraw 0");
        super.withdraw(amount);

        emit Withdrawn(_msgSender(), amount);
    }


    function exit() nonReentrant external {
        withdraw(balanceOf(_msgSender()));
        getReward();
    }


    function getReward() public nonReentrant updateReward(_msgSender()){
        uint256 reward = earned(_msgSender());

        if (reward > 0) {
            rewards[_msgSender()] = 0;

            STAKEBSKT.safeTransfer(_msgSender(), reward);

            emit Rewarded(address(this), _msgSender(), reward);
        }

    }


    function notifyRewardRate(uint256 _reward) public updateReward(address(0)) onlyOwner{

        require(!firstNotify, "Error : Notify rewards allowed once only");

        rewardRate = _reward.div(duration);

        lastUpdateTime = block.timestamp;
        starttime = block.timestamp; 
        periodFinish = block.timestamp.add(duration);

        firstNotify = true;
    }
}

pragma solidity 0.5.0;

contract ReentrancyGuard {











    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor () internal {
        _status = _NOT_ENTERED;
    }


    modifier nonReentrant() {

        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");


        _status = _ENTERED;

        _;



        _status = _NOT_ENTERED;
    }
}

library Math {
    function max(uint256 a, uint256 b) internal pure returns (uint256) {
        return a >= b ? a : b;
    }

    function min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }

    function average(uint256 a, uint256 b) internal pure returns (uint256) {
        return (a / 2) + (b / 2) + (((a % 2) + (b % 2)) / 2);
    }
}

library SafeMath {
    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        require(c >= a, "SafeMath: addition overflow");

        return c;
    }

    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        return sub(a, b, "SafeMath: subtraction overflow");
    }

    function sub(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b <= a, errorMessage);
        uint256 c = a - b;

        return c;
    }

    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        if (a == 0) {
            return 0;
        }

        uint256 c = a * b;
        require(c / a == b, "SafeMath: multiplication overflow");

        return c;
    }

    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        return div(a, b, "SafeMath: division by zero");
    }

    function div(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b > 0, errorMessage);
        uint256 c = a / b;

        return c;
    }

    function mod(uint256 a, uint256 b) internal pure returns (uint256) {
        return mod(a, b, "SafeMath: modulo by zero");
    }

    function mod(
        uint256 a,
        uint256 b,
        string memory errorMessage
    ) internal pure returns (uint256) {
        require(b != 0, errorMessage);
        return a % b;
    }
}

contract Context {
    constructor() internal {}

    function _msgSender() internal view returns (address payable) {
        return msg.sender;
    }

    function _msgData() internal view returns (bytes memory) {
        this;
        return msg.data;
    }
}

contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(
        address indexed previousOwner,
        address indexed newOwner
    );

    constructor() internal {
        _owner = _msgSender();
        emit OwnershipTransferred(address(0), _owner);
    }

    function owner() public view returns (address) {
        return _owner;
    }

    modifier onlyOwner() {
        require(isOwner(), "Ownable: caller is not the owner");
        _;
    }

    function isOwner() public view returns (bool) {
        return _msgSender() == _owner;
    }

    function renounceOwnership() public onlyOwner {
        emit OwnershipTransferred(_owner, address(0));
        _owner = address(0);
    }

    function transferOwnership(address newOwner) public onlyOwner {
        _transferOwnership(newOwner);
    }

    function _transferOwnership(address newOwner) internal {
        require(
            newOwner != address(0),
            "Ownable: new owner is the zero address"
        );
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

